using namespace std;
#define ll long long

int main() {
    int t;
    cin >> t;
    while (t--) {
        long long n, m;
        cin >> n >> m;

        vector<ll> p(n);
        for (int i = 0; i < n; i++) {
            cin >> p[i];
        }

        sort(p.begin(), p.end(), greater<ll>());

        ll tot = 0;
        ll d = 0;

        for (int i = 0; i < n; i++) {
            tot += p[i];
            if (tot >= m) {
                d = i + 1;
                break;
            }
        }

        if (d == 0) {
            cout << -1 << endl;
        } else {
            cout << d << endl;
        }
    }
    return 0;
}

