#include <stdio.h>

int compare(const void *a, const void *b) {
    return (*(long long *)b > *(long long *)a) - (*(long long *)b < *(long long *)a);
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        long long n, m;
        scanf("%lld %lld", &n, &m);
        long long p[n];
        for (int i = 0; i < n; i++) {
            scanf("%lld", &p[i]);
        }
        qsort(p, n, sizeof(long long), compare);

        long long tot = 0, d = 0;

        for (int i = 0; i < n; i++) {
            tot += p[i];
            if (tot >= m) {
                d = i + 1;
                break;
            }
        }

        if (d == 0) {
            printf("-1\n");
        } else {
            printf("%lld\n", d);
        }
    }
    return 0;
}

