function Ammeat(input) {
    const lines = input.trim().split('\n');
    const T = parseInt(lines[0]);

    let index = 1;
    for (let t = 0; t < T; t++) {
        const [n, sum] = lines[index++].split(' ').map(BigInt); // Convert both n and sum to BigInt
        const v = lines[index++].split(' ').map(BigInt); // Convert all values in v to BigInt

        v.sort((a, b) => (b > a ? 1 : -1)); // Sort in descending order using BigInt comparison

        let total = BigInt(0); // Initialize total as BigInt
        let count = 0;

        for (let i = 0; i < n; i++) {
            total += v[i]; // Add BigInt values
            count++;
            if (total >= sum) {
                console.log(count); // Output count when we reach the sum
                break;
            }
        }

        if (total < sum) {
            console.log(-1); // Output -1 if we never reach the sum
        }
    }
}

